"use strict";(self.webpackChunkdocusaurus=self.webpackChunkdocusaurus||[]).push([[5142],{5166:(e,i,a)=>{a.r(i),a.d(i,{assets:()=>l,contentTitle:()=>t,default:()=>p,frontMatter:()=>r,metadata:()=>s,toc:()=>c});var n=a(4848),o=a(8453);const r={title:"Relation - Programs With Common Sense",date:new Date("2007-09-27T00:00:00.000Z"),authors:["fsferrara"],tags:["history","computer-science","artificial-intelligence","ai","mccharty"]},t='Relazione sull\'articolo: "Programs With Common Sense".',s={permalink:"/b/2007/relation-programs-with-common-sense",source:"@site/../blog/2007/relation-programs-with-common-sense.md",title:"Relation - Programs With Common Sense",description:"John McCharty",date:"2007-09-27T00:00:00.000Z",tags:[{inline:!1,label:"History",permalink:"/b/tags/history",description:"history"},{inline:!0,label:"computer-science",permalink:"/b/tags/computer-science"},{inline:!0,label:"artificial-intelligence",permalink:"/b/tags/artificial-intelligence"},{inline:!0,label:"ai",permalink:"/b/tags/ai"},{inline:!0,label:"mccharty",permalink:"/b/tags/mccharty"}],readingTime:5.905,hasTruncateMarker:!0,authors:[{name:"Saverio Ferrara",title:"Software Engineer",url:"https://github.com/fsferrara",page:{permalink:"/b/authors/fsferrara"},socials:{x:"https://x.com/fsferrara",linkedin:"https://www.linkedin.com/in/fsferrara/",github:"https://github.com/fsferrara"},imageURL:"https://github.com/fsferrara.png",key:"fsferrara"}],frontMatter:{title:"Relation - Programs With Common Sense",date:"2007-09-27T00:00:00.000Z",authors:["fsferrara"],tags:["history","computer-science","artificial-intelligence","ai","mccharty"]},unlisted:!1,prevItem:{title:"Loop-Unrolling Technique",permalink:"/b/2009/loop-unrolling-technique"},nextItem:{title:"Relation - On Representations of Problems of Reasoning about Actions",permalink:"/b/2007/relation-on-representations-of-problems-of-reasoning-about-actions"}},l={authorsImageUrls:[void 0]},c=[];function d(e){const i={code:"code",li:"li",ol:"ol",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(i.p,{children:"John McCharty"}),"\n",(0,n.jsx)(i.p,{children:'Nel 1959, quando si parlava pochissimo di "intelligenza artificiale", John McCharty con l\'articolo "Programs with common sense", introduce un programma che ha buonsenso (common sense).'}),"\n",(0,n.jsx)(i.p,{children:'L\'articolo esaminato parla di come un programma pu\xf2 risolvere problemi mediante la manipolazione di un linguaggio formale accettato dal computer, che contiene i pi\xf9 comuni costrutti utilizzati anche nel linguaggio naturale. Lo scopo \xe8 di far svolgere alla macchina un ragionamento verbale elementare, ma con delle facilitazioni: essa \xe8 collegata ad un display video per "parlare" e l\'umano user\xe0 una tastiera per interagire. Il programma introdotto da McCharty \xe8 chiamato "Advice Taker" e pu\xf2 eseguire azioni al suo interno (ad esempio muovere una frase, o espressione formale, nelle sue liste) e dare conclusioni (stampare frasi dichiarative o imperative).'}),"\n",(0,n.jsx)(i.p,{children:"La differenza tra l'Advice Taker ed altri programmi proposti all'epoca sta nel fatto che mentre gli altri programmi contenevano le euristiche di valutazione all'interno della procedura di deduzione, nell'Advice Taker le euristiche sono state descritte nel linguaggio formale stesso, in modo da avere una maggiore flessibilit\xe0. Si potr\xe0 cambiare il comportamento dell'Advice Taker; possiamo istruirlo sull'ambiente nel quale lavora, e sullo scopo che deve perseguire, il tutto in tempo relativamente breve: infatti, istruire l'Advice Taker richiede poca familiarit\xe0 con il programma e con le conoscenze passate. L'aggettivo common sense si basa sul fatto che pi\xf9 il programma \xe8 istruito, pi\xf9 ha buonsenso: questo concetto ha molto in comune con il \"buonsenso\" degli umani."}),"\n",(0,n.jsx)(i.p,{children:"Prima di introdurre il funzionamento del programma, McCharty illustra cinque caratteristiche (non pienamente condivise da Marvin Minsky, altro studioso dell'intelligenza artificiale) che un sistema deve avere per essere capace di sviluppare intelligenza paragonabile a quella degli umani:"}),"\n",(0,n.jsxs)(i.ol,{children:["\n",(0,n.jsx)(i.li,{children:"Ogni comportamento deve essere rappresentabile nel sistema;"}),"\n",(0,n.jsx)(i.li,{children:"Un cambiamento nel comportamento deve essere esprimibile semplicemente;"}),"\n",(0,n.jsx)(i.li,{children:"Tutti gli aspetti del comportamento devono essere migliorabili;"}),"\n",(0,n.jsx)(i.li,{children:"Oltre al successo e al fallimento, la macchina deve comprendere il concetto di successo parziale;"}),"\n",(0,n.jsx)(i.li,{children:"Il sistema deve essere in grado di programmarsi da solo automi o subroutine che potr\xe0 poi eseguire."}),"\n"]}),"\n",(0,n.jsx)(i.p,{children:"Certo un sistema con queste caratteristiche \xe8 molto difficile da implementare, specialmente nell'anno in cui l'articolo \xe8 stato scritto. McCharty, infatti, nella progettazione dell'Advice Taker si concentra solo sulla seconda caratteristica, cercando un modo semplice ed intelligente per rappresentare cambiamenti di comportamento."}),"\n",(0,n.jsx)(i.p,{children:"Per far pensare la macchina, sono preferite preposizioni dichiarative anzich\xe9 preposizioni imperative. Di fatto le preposizioni imperative non badano a conoscenze precedenti, e rappresentano solo ordini da eseguire, mentre le preposizioni dichiarative sfruttano le conoscenze precedenti, hanno conseguenze logiche, e lo stato del sistema non \xe8 sconvolto dall'effetto che una proposizione pu\xf2 avere. Inoltre, siccome l'ordine di presentazione delle proposizione dichiarative non \xe8 rilevante, la macchina pu\xf2 avere ripensamenti."}),"\n",(0,n.jsx)(i.p,{children:"I tre componenti principali dell'Advice Taker sono:"}),"\n",(0,n.jsx)(i.p,{children:"Espressioni regolari: Il nome \"Advice Taker\" si riferisce a qualcosa che accetta consigli (advice). Questi consigli sono dati dall'umano alla macchina sotto forma di espressioni regolari, di conseguenza l'Advice Taker deve essere in grado di rappresentare e memorizzare al suo interno espressioni di questo tipo. Un'espressione pu\xf2 essere ad esempio una proposizione dichiarativa o un nome di entit\xe0, e ad ognuna di esse \xe8 associata una precisa regola di inferenza data dalla combinazione del modus ponens con la sostituzione di variabili; con un insieme iniziali di espressioni, mediante un'apposita procedura di deduzione, si pu\xf2 immediatamente dedurre un insieme di conclusioni. Oltre alle espressioni regolari, si possono memorizzare anche individui, funzioni, e programmi. L'insieme di tutte le espressioni memorizzate all'interno dell'Advice Taker rappresenta la sua conoscenza."}),"\n",(0,n.jsx)(i.p,{children:"Procedura di deduzione: La procedura di deduzione non user\xe0 un'euristica di carattere semantico! Questo rende l'euristica stessa non dipendente dall'argomento trattato, quindi si punta a risolvere qualsiasi problema, senza legarsi ad un tipo specifico.  Applicare simultaneamente la procedura di deduzione su tutta la conoscenza dell'Advice Taker pu\xf2 essere molto oneroso computazionalmente, e render\xe0 lenta la reazione della macchina. A questo proposito ci saranno alcune procedure che in base al problema da risolvere preleveranno dalla conoscenza l'insieme di tutte le espressioni interessanti al problema stesso, per poi applicare la procedura di deduzione solo su questo sottoinsieme. E' evidente che la procedura di deduzione immediata non conterr\xe0 l'intelligenza dell'Advice Taker, ma essa sar\xe0 inglobata nelle procedure atte a formare le liste su cui operare."}),"\n",(0,n.jsx)(i.p,{children:"Oggetti e liste di attributi: Tutte le espressioni che rappresentano il nome di un'entit\xe0 hanno associate ad esse una lista di attributi contenente le propriet\xe0 dell'entit\xe0 stessa. Pu\xf2 capitare che un'entit\xe0 non abbia aggiuntivi, ma solo informazioni ricavabili dal nome stesso; in questo caso per l'entit\xe0 non sar\xe0 presente una lista di propriet\xe0. Un esempio \xe8 rappresentato del numero 3812 il quale ci offre tutte le informazioni dal nome stesso. Le liste di attributi hanno anche una seconda utilit\xe0: se per dedurre un'informazione dell'entit\xe0 \xe8 stato particolarmente costoso, questa informazione si pu\xf2 registrare all'interno della lista."}),"\n",(0,n.jsx)(i.p,{children:"Il funzionamento del programma prevede di svolgere ciclicamente i seguenti cinque passi:"}),"\n",(0,n.jsxs)(i.p,{children:[(0,n.jsx)(i.strong,{children:"Passo 1"}),": Si parte da una lista di premesse (espressioni regolari) e d'individui.\n",(0,n.jsx)(i.strong,{children:"Passo 2"}),": Alla lista si applica la procedura di deduzione, e abbiamo in output una lista di conclusioni.\n",(0,n.jsx)(i.strong,{children:"Passo 3"}),": Dalla lista di conclusioni estrapoliamo tutte le proposizioni imperative dedotte.\n",(0,n.jsx)(i.strong,{children:"Passo 4"}),": Gli imperativi sono ubbiditi.\n",(0,n.jsx)(i.strong,{children:"Passo 5"}),": Tra gli imperativi c'\xe8 la procedura che deduce e ubbidisce, e questo rende ciclico il funzionamento del programma."]}),"\n",(0,n.jsx)(i.p,{children:"Com'esempio \xe8 considerato il problema \"Come raggiungere l'aeroporto se mi trovo alla scrivania nella mia casa\". La prima cosa da fare \xe8 istruire il programma sull'ambiente e sul problema da risolvere, mediante l'introduzione di espressioni regolari."}),"\n",(0,n.jsx)(i.p,{children:"Il primo predicato introdotto \xe8"}),"\n",(0,n.jsx)(i.pre,{children:(0,n.jsx)(i.code,{children:"at(x,y)\n"})}),"\n",(0,n.jsx)(i.p,{children:'che \xe8 una formalizzazione di "x is at y", quindi dire'}),"\n",(0,n.jsx)(i.pre,{children:(0,n.jsx)(i.code,{children:"at(io,scrivania)\n"})}),"\n",(0,n.jsx)(i.p,{children:"significa che io mi trovo alla scrivania."}),"\n",(0,n.jsx)(i.p,{children:"Di questo predicato \xe8 possibile esprimere la propriet\xe0 transitiva in questo modo:"}),"\n",(0,n.jsx)(i.pre,{children:(0,n.jsx)(i.code,{children:"at(x,y), at(y,z)  ->  at(x,z)\n"})}),"\n",(0,n.jsx)(i.p,{children:"In questo modo sono inserite tutte le conoscenze utili all'Advice Taker per risolvere il problema, come le seguenti propriet\xe0:"}),"\n",(0,n.jsxs)(i.ul,{children:["\n",(0,n.jsx)(i.li,{children:'"raggiungibilit\xe0 di un luogo a piedi",'}),"\n",(0,n.jsx)(i.li,{children:'"raggiungibilit\xe0 di un luogo con l\'auto",'}),"\n",(0,n.jsx)(i.li,{children:'"andare in un luogo",'}),"\n",(0,n.jsx)(i.li,{children:'"possibilit\xe0 di andare in un luogo".'}),"\n"]}),"\n",(0,n.jsx)(i.p,{children:"Infine la propriet\xe0 dalla quale parte il processo di deduzione:"}),"\n",(0,n.jsx)(i.pre,{children:(0,n.jsx)(i.code,{children:"want(at(io,aeroporto))\n"})}),"\n",(0,n.jsx)(i.p,{children:"Quest'ultima esprime l'obiettivo (goal) che la macchina deve perseguire. A questo punto ci sono due importanti problemi da risolvere:"}),"\n",(0,n.jsxs)(i.ol,{children:["\n",(0,n.jsx)(i.li,{children:"Estrapolare dalla conoscenza le premesse utili a risolvere il problema;"}),"\n",(0,n.jsx)(i.li,{children:"Applicare il processo di deduzione alle premesse estrapolate."}),"\n"]}),"\n",(0,n.jsx)(i.p,{children:"Questi due problemi non trovano soluzione nell'articolo di McCharty."}),"\n",(0,n.jsx)(i.p,{children:'Sicuramente l\'Advice Taker parte con due premesse; la prima \xe8 in(io,scrivania) che \xe8 dedotta dalla domanda "Dove mi trovo?", mentre la seconda \xe8 quella che esprime il goal da perseguire: want(at(io,aeroporto)). Quest\'ultima \xe8 inserita in una lista principale L, e in base al contenuto di questa lista \xe8 creata una lista ausiliaria (chiamata "observation of the main list"). Questa lista ausiliaria, insieme ad un\'altra lista delle "azioni da compiere" sono utilizzate dalla procedura di deduzione per perseguire lo scopo.'}),"\n",(0,n.jsx)(i.p,{children:"McCharty non s'inoltra troppo nei dettagli della soluzione, in effetti, questo articolo ha lo scopo di introdurre le liste, di espressioni formali o di propriet\xe0, e di chiarire la sistemazione delle regole euristiche."})]})}function p(e={}){const{wrapper:i}={...(0,o.R)(),...e.components};return i?(0,n.jsx)(i,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},8453:(e,i,a)=>{a.d(i,{R:()=>t,x:()=>s});var n=a(6540);const o={},r=n.createContext(o);function t(e){const i=n.useContext(r);return n.useMemo((function(){return"function"==typeof e?e(i):{...i,...e}}),[i,e])}function s(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:t(e.components),n.createElement(r.Provider,{value:i},e.children)}}}]);